class Solution:
    def largestCombination(self, candidates):
        best = 0
        for bit in range(25):
            mask = 1 << bit
            c = 0
            for x in candidates:
                if x & mask:
                    c += 1
            if c > best:
                best = c
        return best

solutions.python:
class Solution:
    def largestCombination(self, candidates):
        counts = [0] * 24
        for x in candidates:
            b = 0
            while x:
                if x & 1:
                    counts[b] += 1
                x >>= 1
                b += 1
        return max(counts)

