var largestCombination = function(candidates) {
    const counts = new Array(24).fill(0);
    for (let x of candidates) {
        let b = 0;
        while (x) {
            if (x & 1) counts[b]++;
            x >>>= 1;
            b++;
        }
    }
    return Math.max(...counts);
};
